//用于发送指定data_type和devid的命令

import proto from '@/utils/sdkapi_pb.js'

export function useCommand(store) {
  const sendGetStatusData = (dataType, devid) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_GET_STATUS_DATA)

    // data_type 参数
    let paramData = request.addParamData()
    paramData.setKey('data_type')
    paramData.setVal(dataType)

    // devid 参数（如果有）
    if (devid) {
      paramData = request.addParamData()
      paramData.setKey('devid')
      const devidStr = Array.isArray(devid) ? devid.join(',') : devid.toString()
      paramData.setVal(devidStr)
    }

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  const sendConnectWifi = (devid, ssid, password) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_CONNECT_WIFI)

    let paramData = request.addParamData()
    paramData.setKey('devid')
    paramData.setVal(devid.toString())

    paramData = request.addParamData()
    paramData.setKey('ssid')
    paramData.setVal(ssid)

    paramData = request.addParamData()
    paramData.setKey('password')
    paramData.setVal(password)

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  const sendConfigData = (devName, configFile, paramList) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_SET_CONFIG_DATA)

    const config_data = request.addConfigData()
    config_data.setDevName(devName)
    config_data.setConfigFile(configFile)

    paramList.forEach(({ key, val }) => {
      const paramData = new proto.ParamData()
      paramData.setKey(key)
      paramData.setVal(val)
      config_data.addParamData(paramData)
    })

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  const sendLogExtractCommand = (
    devid,
    logType,
    startTime,
    endTime
    // userdata
  ) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_RUN_LOG_EXTRACT)
    // request.getHeader().setUserdata(userdata) //存储用于区分任务的信息，每次请求随机生成，后端后续回复会返回

    let param = request.addParamData()
    param.setKey('devid')
    param.setVal(devid) // x86, orin

    param = request.addParamData()
    param.setKey('type')
    param.setVal(logType) //app, bag, sys, kernel

    param = request.addParamData()
    param.setKey('start_time')
    param.setVal(startTime)

    param = request.addParamData()
    param.setKey('end_time')
    param.setVal(endTime)

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  const sendAudioCommand = (cmdtype, audioId) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_RUN_DEVICE_CONTROL)

    let param = request.addParamData()
    param.setKey('cmdtype')
    param.setVal(cmdtype) // "PLAY_AUDIO_FILE" or "DELETE_AUDIO_FILE"

    param = request.addParamData()
    param.setKey('audio_id')
    param.setVal(audioId)

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  const sendActionCommand = (actionId) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_RUN_ACTION)

    let param = request.addParamData()
    param.setKey('action_id')
    param.setVal(actionId)

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  return {
    sendGetStatusData,
    sendConnectWifi,
    sendConfigData,
    sendLogExtractCommand,
    sendAudioCommand,
    sendActionCommand
  }
}
