<template>
  <div class="flex-direction-column">
    <!-- 基本信息 -->
    <div class="g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">基本信息</span>
      </div>
      <div class="container-content">
        <div class="g-double-column-layout">
          <div class="column">
            <div class="g-kv-pair">
              <div class="label">机器人ID</div>
              <div class="value">{{ robotData?.robotId || '-' }}</div>
            </div>
            <div class="g-kv-pair">
              <div class="label">出厂日期</div>
              <div class="value">{{ robotData?.robotDate || '-' }}</div>
            </div>
          </div>
          <div class="column">
            <div class="g-kv-pair">
              <div class="label">机器人名称</div>
              <div class="value">{{ robotData?.robotName || '-' }}</div>
            </div>
            <div class="g-kv-pair">
              <div class="label">描述信息</div>
              <div class="value">{{ robotData?.robotDesp || '-' }}</div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 版本信息 -->
    <div class="g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">版本信息</span>
      </div>
      <div class="container-content">
        <div class="version-grid">
          <div
            v-for="(item, index) in sortedVersionDataList"
            :key="index"
            class="g-kv-pair"
          >
            <div class="label">{{ capitalizeFirst(item.devdesp) }}</div>
            <div class="value">{{ item.version || '-' }}</div>
          </div>
        </div>
      </div>
    </div>

    <!-- 系统信息 -->
    <div class="g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">系统信息</span>
      </div>
      <div class="container-content flex-direction-column">
        <div class="g-section-layout">
          <div
            v-for="(item, index) in sortedSystemDataList"
            :key="index"
            class="section"
          >
            <h3>{{ capitalizeFirst(item.devdesp) }}</h3>
            <div class="g-kv-pair">
              <div class="label">操作系统</div>
              <div class="value">{{ capitalizeFirst(item.devdesp) }}</div>
            </div>
            <div class="g-kv-pair">
              <div class="label">系统时间</div>
              <div class="value">{{ formatTimestamp(item.timestamp) }}</div>
            </div>
            <div class="g-kv-pair">
              <div class="label">Wi-Fi SSID</div>
              <div class="value">{{ item.wifiSsid || '-' }}</div>
            </div>
            <div class="g-kv-pair">
              <div class="label">IP</div>
              <div class="value-with-button">
                <div class="value">{{ item.wifiIp }}</div>
                <div class="g-button" @click="handleConnect(item)">连接</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- Dialog -->
  <el-dialog
    v-model="dialogVisible"
    title="连接Wi-Fi"
    width="30%"
    :close-on-click-modal="false"
  >
    <div class="wifi-form">
      <div class="form-item">
        <div class="form-label">SSID：</div>
        <el-input v-model="wifiForm.ssid" placeholder="请输入" />
      </div>
      <div class="form-item">
        <div class="form-label">Password：</div>
        <el-input
          v-model="wifiForm.password"
          type="password"
          placeholder="请输入"
        />
      </div>
    </div>
    <template #footer>
      <span class="dialog-footer">
        <el-button @click="dialogVisible = false">取消</el-button>
        <el-button type="primary" @click="handleWifiSubmit">连接</el-button>
      </span>
    </template>
  </el-dialog>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import proto from '@/utils/sdkapi_pb.js'

import { ElMessage, ElDialog, ElButton, ElInput } from 'element-plus'
import { useCommand } from '@/hooks/useCommand'

import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

const store = useWslStore()
const { received, isConnected, wifiCommandResult } = storeToRefs(store)

import { useSortData } from '@/hooks/useSortData'

// 基本信息数据
const robotData = computed(() => {
  const data = received.value?.statusData?.robotDataList?.[0]
  if (!data || data.length === 0) {
    return {
      robotDesp: '暂无'
    }
  }
  return data
})

// 版本信息数据
const versionDataList = computed(() => {
  const data = received.value?.statusData?.versionDataList
  if (!data || data.length === 0) {
    return [
      {
        devdesp: '暂无'
      }
    ]
  }
  return data
})
const sortedVersionDataList = useSortData(versionDataList, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

// 系统信息数据
const systemDataList = computed(() => {
  const data = received.value?.statusData?.systemDataList
  if (!data || data.length === 0) {
    return [
      {
        devdesp: '暂无'
      }
    ]
  }
  return data
})
const sortedSystemDataList = useSortData(systemDataList, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

// 首字母大写工具函数
const capitalizeFirst = (str) => {
  if (!str) return '-'
  return str.charAt(0).toUpperCase() + str.slice(1)
}

//wifi连接部分
const { sendConnectWifi } = useCommand(store)

// Dialog相关
const dialogVisible = ref(false)
const currentDevice = ref(null)
const isConnecting = ref(false)
const wifiForm = ref({
  ssid: '',
  password: ''
})

// 监听连接状态和命令结果
watch(
  () => wifiCommandResult.value,
  (result) => {
    if (!result || !currentDevice.value) return // 添加安全检查

    if (result.command === proto.Command.CMD_CONNECT_WIFI) {
      if (result.success) {
        ElMessage({
          message: `已连接${currentDevice.value.devname} Wi-Fi`,
          type: 'success'
        })
        dialogVisible.value = false
      } else {
        ElMessage({
          message: `错误信息：${result.message}`,
          type: 'error'
        })
      }
      // 重置命令结果
      store.wifiCommandResult = null
      isConnecting.value = false
    }
  },
  {
    deep: true // 添加深度监听
  }
)

// 处理连接按钮点击
const handleConnect = (item) => {
  currentDevice.value = item
  dialogVisible.value = true
}

// 处理wifi连接提交
const handleWifiSubmit = () => {
  if (!wifiForm.value.ssid || !wifiForm.value.password) {
    ElMessage({
      message: '请填写完整信息',
      type: 'warning'
    })
    return
  }

  isConnecting.value = true // 设置连接中状态

  sendConnectWifi(
    currentDevice.value.devid,
    wifiForm.value.ssid,
    wifiForm.value.password
  )
  // dialogVisible.value = false
  wifiForm.value = { ssid: '', password: '' }
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      const request = new proto.Request()
      request.setCommand(proto.Command.CMD_GET_STATUS_DATA)
      const data = request.serializeBinary()
      store.websocketSendData({ data })
    }
  },
  { immediate: true }
)
</script>

<style lang="less" scoped>
.version-grid {
  width: 100%;

  display: grid;
  grid-template-columns: repeat(2, 1fr);

  gap: 4%;
  margin-top: 20px;
  margin-bottom: 40px;
}

h3 {
  margin-bottom: 10px;
}

//wifi
.value-with-button {
  flex: 0.35;
  display: flex;
  align-items: center;
  justify-content: flex-start; // 内容左对齐
  gap: 10px;

  .value {
    color: #186c3c;
    font-size: 16px;
    font-weight: 500;

    &:empty::before {
      // 当value为空时显示等待连接-红色
      content: '等待连接……';
      color: #ff4d4f;
    }
  }
}

.wifi-form {
  .form-item {
    margin-bottom: 20px;

    .form-label {
      margin-bottom: 8px;
    }
  }
}

.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
}
</style>
